  name: 'Объект',
  getName() {
    return this.name;
  }
};

// Вызов как метод — this = obj
obj.getName(); // 'Объект'

// Вызов без контекста — this = undefined
const fn = obj.getName;
fn(); // TypeError: Cannot read property 'name' of undefined
